// ProductCard.js
import React from 'react';
import { useOrderContext } from './OrderCartContext';
import { useNavigate } from 'react-router-dom';

const ProductCard = ({ id, name, price, description }) => {
  const { addToOrder, getItemQuantity } = useOrderContext();
  const navigate = useNavigate();
  
  const currentQuantity = getItemQuantity(id);

  const handleIncrement = () => {
    addToOrder(id, 1);
  };

  const handleDecrement = () => {
    addToOrder(id, -1);
  };

  const handleAddToCart = () => {
    if (currentQuantity > 0) {
      alert(`${currentQuantity} ${name}(s) have been added to the cart!`);
    }
  };

  const handleGoToCart = () => {
    navigate('/cart');
  };

  return (
    <div className="card">
      <div className="card-details">
        <h3 className="cake-name">{name}</h3>
        <p className="cake-description">{description}</p>
        <p className="cake-price">Price: ${price.toFixed(2)}</p>
        <div className="quantity-controls">
          <button 
            onClick={handleDecrement} 
            className="quantity-btn" 
            disabled={currentQuantity === 0}
            aria-label={`Decrease quantity of ${name}`}
          >
            -
          </button>
          <span className="quantity-display">{currentQuantity}</span>
          <button 
            onClick={handleIncrement} 
            className="quantity-btn" 
            aria-label={`Increase quantity of ${name}`}
          >
            +
          </button>
        </div>
        <button 
          onClick={handleAddToCart} 
          className="add-to-cart-btn"
          disabled={currentQuantity === 0}
          aria-label={`Add ${currentQuantity} ${name}(s) to cart`}
        >
          Add to Cart
        </button>
        <button
          onClick={handleGoToCart}
          className="go-to-cart-btn"
          aria-label="Go to cart"
        >
          Go to Cart
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
